// API endpoint: GET/POST /api/automated-protocol-optimization/experiments
// Story 9.3: Automated protocol optimization - Protocol A/B testing experiments
// Generated by: VoidBeast V4.0

import { type NextRequest, NextResponse } from 'next/server';
import { AutomatedProtocolOptimizationService } from '../../../lib/services/automated-protocol-optimization';
import { createProtocolExperimentSchema } from '../../../lib/validations/automated-protocol-optimization';

const service = new AutomatedProtocolOptimizationService();

// GET: List protocol experiments with optional filters
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);

    const filters = {
      status: searchParams.get('status') || undefined,
      experiment_type: searchParams.get('experiment_type') || undefined,
      page: Number.parseInt(searchParams.get('page') || '1', 10),
      per_page: Number.parseInt(searchParams.get('per_page') || '20', 10),
    };

    const result = await service.getProtocolExperiments(filters);

    return NextResponse.json({
      success: true,
      data: result.data,
      pagination: {
        page: filters.page,
        per_page: filters.per_page,
        total: result.total,
        total_pages: Math.ceil(result.total / filters.per_page),
      },
    });
  } catch (error) {
    return NextResponse.json(
      {
        success: false,
        error: 'Failed to fetch protocol experiments',
        details: error instanceof Error ? error.message : 'Unknown error',
      },
      { status: 500 }
    );
  }
}

// POST: Create new protocol experiment
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();

    // Validate request data
    const validation = createProtocolExperimentSchema.safeParse(body);
    if (!validation.success) {
      return NextResponse.json(
        {
          success: false,
          error: 'Validation failed',
          details: validation.error.format(),
        },
        { status: 400 }
      );
    }

    const protocolExperiment = await service.createProtocolExperiment(
      validation.data
    );

    return NextResponse.json(
      {
        success: true,
        data: protocolExperiment,
        message: 'Protocol experiment created successfully',
      },
      { status: 201 }
    );
  } catch (error) {
    return NextResponse.json(
      {
        success: false,
        error: 'Failed to create protocol experiment',
        details: error instanceof Error ? error.message : 'Unknown error',
      },
      { status: 500 }
    );
  }
}
